import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.C58al07P.js";const h=JSON.parse('{"title":"Configuration Google Cloud","description":"","frontmatter":{},"headers":[],"relativePath":"fr/installation/google-cloud.md","filePath":"fr/installation/google-cloud.md"}'),s={name:"fr/installation/google-cloud.md"};function l(r,e,n,c,d,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="configuration-google-cloud" tabindex="-1">Configuration Google Cloud <a class="header-anchor" href="#configuration-google-cloud" aria-label="Permalink to &quot;Configuration Google Cloud&quot;">​</a></h1><p>Guide pas à pas pour configurer les credentials OAuth2 nécessaires à Nid.</p><hr><h2 id="_1-creer-un-projet-google-cloud" tabindex="-1">1. Créer un projet Google Cloud <a class="header-anchor" href="#_1-creer-un-projet-google-cloud" aria-label="Permalink to &quot;1. Créer un projet Google Cloud&quot;">​</a></h2><ol><li>Rendez-vous sur <a href="https://console.cloud.google.com" target="_blank" rel="noreferrer">console.cloud.google.com</a></li><li>Cliquez sur le sélecteur de projet en haut → <strong>Nouveau projet</strong></li><li>Nommez-le (ex. <code>nid</code>) et cliquez sur <strong>Créer</strong></li></ol><hr><h2 id="_2-activer-l-api-gmail" tabindex="-1">2. Activer l&#39;API Gmail <a class="header-anchor" href="#_2-activer-l-api-gmail" aria-label="Permalink to &quot;2. Activer l&#39;API Gmail&quot;">​</a></h2><ol><li>Dans le menu latéral : <strong>APIs &amp; Services</strong> → <strong>Bibliothèque</strong></li><li>Recherchez <strong>Gmail API</strong></li><li>Cliquez sur <strong>Activer</strong></li></ol><hr><h2 id="_3-configurer-l-ecran-de-consentement-oauth" tabindex="-1">3. Configurer l&#39;écran de consentement OAuth <a class="header-anchor" href="#_3-configurer-l-ecran-de-consentement-oauth" aria-label="Permalink to &quot;3. Configurer l&#39;écran de consentement OAuth&quot;">​</a></h2><ol><li><strong>APIs &amp; Services</strong> → <strong>Écran de consentement OAuth</strong></li><li>Choisissez le type : <ul><li><strong>Interne</strong> : si vous avez un compte Google Workspace (pas d&#39;écran d&#39;avertissement)</li><li><strong>Externe</strong> : pour les comptes Gmail personnels (nécessite des utilisateurs de test)</li></ul></li><li>Renseignez : <ul><li>Nom de l&#39;application : <code>Nid</code></li><li>Email d&#39;assistance : votre email</li><li>Domaine autorisé : votre domaine (ou laissez vide pour localhost)</li></ul></li><li>Ajoutez les <strong>scopes</strong> : <ul><li><code>https://www.googleapis.com/auth/gmail.modify</code></li><li><code>https://www.googleapis.com/auth/gmail.labels</code></li><li><code>https://www.googleapis.com/auth/userinfo.email</code></li><li><code>https://www.googleapis.com/auth/userinfo.profile</code></li></ul></li><li>Si <strong>Externe</strong> : ajoutez votre email en tant qu&#39;<strong>utilisateur de test</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">Application en mode Test</p><p>Tant que l&#39;application est en mode &quot;Test&quot;, Google affichera un écran d&#39;avertissement lors de la connexion. C&#39;est normal pour un usage personnel. Cliquez sur <strong>Paramètres avancés</strong> → <strong>Accéder à nid (non sécurisé)</strong> pour continuer.</p></div><hr><h2 id="_4-creer-les-credentials-oauth2" tabindex="-1">4. Créer les credentials OAuth2 <a class="header-anchor" href="#_4-creer-les-credentials-oauth2" aria-label="Permalink to &quot;4. Créer les credentials OAuth2&quot;">​</a></h2><ol><li><strong>APIs &amp; Services</strong> → <strong>Identifiants</strong> → <strong>Créer des identifiants</strong> → <strong>ID client OAuth 2.0</strong></li><li>Type d&#39;application : <strong>Application Web</strong></li><li>Nom : <code>Nid</code></li><li>Ajoutez <strong>deux</strong> URIs de redirection autorisées :</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:3000/api/auth/gmail/callback</span></span>\n<span class="line"><span>http://localhost:3000/api/auth/google/callback</span></span></code></pre></div><table tabindex="0"><thead><tr><th>URI</th><th>Rôle</th></tr></thead><tbody><tr><td><code>/api/auth/gmail/callback</code></td><td>Connexion d&#39;un compte Gmail à l&#39;application (OAuth2 Gmail)</td></tr><tr><td><code>/api/auth/google/callback</code></td><td>Inscription / connexion via Google SSO</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Domaine personnalisé</p><p>Si vous exposez l&#39;application sur un domaine (ex. <code>https://gmail.monnas.fr</code>), remplacez <code>http://localhost:3000</code> par votre URL publique dans les URIs de callback <strong>et</strong> dans la variable <code>FRONTEND_URL</code> du <code>.env</code>.</p></div><ol start="5"><li>Cliquez sur <strong>Créer</strong></li><li>Notez le <strong>Client ID</strong> et le <strong>Client Secret</strong> → à reporter dans votre <code>.env</code></li></ol><hr><h2 id="_5-reporter-dans-le-env" tabindex="-1">5. Reporter dans le <code>.env</code> <a class="header-anchor" href="#_5-reporter-dans-le-env" aria-label="Permalink to &quot;5. Reporter dans le `.env`&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_CLIENT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">123456789-xxxxxxxxxx.apps.googleusercontent.com</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_CLIENT_SECRET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">GOCSPX-xxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><p>Les URIs de callback sont dérivées automatiquement de <code>FRONTEND_URL</code> en Docker production. En développement, définissez-les explicitement :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_REDIRECT_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:4000/api/auth/gmail/callback</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_SSO_REDIRECT_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:4000/api/auth/google/callback</span></span></code></pre></div><hr><h2 id="resolution-de-problemes" tabindex="-1">Résolution de problèmes <a class="header-anchor" href="#resolution-de-problemes" aria-label="Permalink to &quot;Résolution de problèmes&quot;">​</a></h2><h3 id="erreur-redirect-uri-mismatch" tabindex="-1">Erreur <code>redirect_uri_mismatch</code> <a class="header-anchor" href="#erreur-redirect-uri-mismatch" aria-label="Permalink to &quot;Erreur `redirect_uri_mismatch`&quot;">​</a></h3><p>L&#39;URI de callback configurée dans Google Cloud ne correspond pas exactement à celle utilisée par l&#39;application. Vérifiez :</p><ul><li>Le protocole (<code>http</code> vs <code>https</code>)</li><li>Le port (<code>3000</code> en prod, <code>4000</code> en dev)</li><li>Le path exact (pas de <code>/</code> en trop)</li></ul><h3 id="erreur-invalid-client" tabindex="-1">Erreur <code>invalid_client</code> <a class="header-anchor" href="#erreur-invalid-client" aria-label="Permalink to &quot;Erreur `invalid_client`&quot;">​</a></h3><p>Le Client ID ou Client Secret est incorrect. Vérifiez vos variables <code>GOOGLE_CLIENT_ID</code> et <code>GOOGLE_CLIENT_SECRET</code>.</p><h3 id="l-ecran-d-avertissement-google-apparait" tabindex="-1">L&#39;écran d&#39;avertissement Google apparaît <a class="header-anchor" href="#l-ecran-d-avertissement-google-apparait" aria-label="Permalink to &quot;L&#39;écran d&#39;avertissement Google apparaît&quot;">​</a></h3><p>C&#39;est normal si l&#39;application est en mode &quot;Test&quot;. Pour un usage personnel self-hosted, vous pouvez ignorer cet avertissement. Pour le supprimer, publiez votre application Google Cloud (nécessite une vérification OAuth par Google).</p><h3 id="le-refresh-token-n-est-pas-recu" tabindex="-1">Le refresh token n&#39;est pas reçu <a class="header-anchor" href="#le-refresh-token-n-est-pas-recu" aria-label="Permalink to &quot;Le refresh token n&#39;est pas reçu&quot;">​</a></h3><p>Google ne retourne le <code>refresh_token</code> qu&#39;au <strong>premier</strong> consentement. Si vous reconnectez un compte Gmail déjà autorisé :</p><ol><li>Allez sur <a href="https://myaccount.google.com/permissions" target="_blank" rel="noreferrer">myaccount.google.com/permissions</a></li><li>Révoquez l&#39;accès de Nid</li><li>Reconnectez le compte — le refresh token sera émis à nouveau</li></ol>',36)])])}const g=o(s,[["render",l]]);export{h as __pageData,g as default};
